    allocator.deallocate(block2);

    // Additional demonstration of free list management
    std::uint64_t* block3 = allocator.allocate();
    allocator.deallocate(block3);

    // The free list operations are demonstrated through the allocate/deallocate cycle
    // push() adds to head, pop() removes from head (LIFO behavior)
}
```

