std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to hold the written data
    std::vector<uint8_t> buffer;

    // Create a write adaptor for the buffer
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Track total bytes written
    std::size_t total_written = 0;

    // Write each chunk separately
    for (const auto& chunk : chunks) {
        // Check available space before writing
        auto available_space = adaptor.free();

        // If chunk is larger than available space, write only what fits
        std::size_t chunk_to_write = std::min(chunk.size(), available_space);

        // Write the chunk
        adaptor.write(chunk.data(), chunk_to_write);

        // Update total written
        total_written += chunk_to_write;

        // If we couldn't write the entire chunk, break to avoid infinite loop
        if (chunk_to_write < chunk.size()) {
            break;
        }
    }

    // Return the final buffer size
    return adaptor.size();
}

